- A "significant upswing" refers to an increase in graduation rates of more than 10%; 
- Institutions with "relatively selective admissions" are those with an admission rate less than 0.5, which means they accept less than 50% of applicants; 
- "Affordable tuition" in this context refers to a tuition fee less than $20,000.

sql:
SELECT AVG(tuition_fee) 
FROM institutions 
WHERE state_id = (SELECT state_id FROM states WHERE state_name = 'Maryland');

SELECT COUNT(DISTINCT institution_id) AS number_of_institutions
FROM degrees
WHERE degree_name = 'Master of Business Administration';

SELECT degree_level, AVG(average_salary) AS average_salary
FROM degrees
GROUP BY degree_level;

WITH avg_tuition AS (
    SELECT AVG(tuition_fee) as avg_fee FROM institutions
)
SELECT institution_id, institution_name, tuition_fee
FROM institutions
WHERE tuition_fee > (SELECT avg_fee FROM avg_tuition);
